/* ============================================================================
   @phlix/ui — Motion scale tokens (Nocturne, R0.1)

   Theme-invariant easing + duration scale. Consumed by the primitives (R0.4)
   and the transition primitives <Reveal>/<PageTransition> (R0.5). Reduced-motion
   handling lives with those primitives + the global reset in index.css.
   ============================================================================ */
:root {
  --ease-out:      cubic-bezier(0.22, 1, 0.36, 1);    /* default — decelerate */
  --ease-spring:   cubic-bezier(0.34, 1.56, 0.64, 1); /* icon pops, big-play */
  --ease-standard: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-in:       cubic-bezier(0.4, 0, 1, 1);

  --dur-fast:   120ms;   /* hover bg, small state */
  --dur-base:   200ms;
  --dur-slow:   320ms;   /* card lift, overlay reveal */
  --dur-slower: 480ms;   /* poster zoom, image fade-in */
}

