  // `tokens.spacing/radius/shadow/motion/typography` convenience objects.
  const categoryFor = (key) => {
    if (key.startsWith('--space-')) return 'spacing';
    if (key.startsWith('--radius-')) return 'radius';
    if (
      key.startsWith('--shadow-') ||
      key.startsWith('--glow-')
