    if (key.startsWith('--ease-') || key.startsWith('--dur-')) return 'motion';
    if (
      key.startsWith('--font-') ||
      key.startsWith('--fw-') ||
      key.startsWith('--text-') ||
      key.startsWith('--tracking-') ||
      key.startsWith('--leading-')
    )
      return 'typography';
    return null;
  };
